import React, { useEffect, useState } from "react";
import Home from "./Home";

function App() {
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
    }, 2000); // splash screen time (2 sec)

    return () => clearTimeout(timer);
  }, []);

  // 🔹 Splash Screen
  if (loading) {
    return (
      <div style={styles.loader}>
        <img
          src="https://cdn-icons-png.flaticon.com/512/2966/2966485.png"
          alt="DocBook Logo"
          style={styles.logo}
        />
        <h1 style={styles.title}>DocBook</h1>
        <p style={styles.subtitle}>Your Health, Our Priority</p>
      </div>
    );
  }

  // 🔹 Main App
  return <Home />;
}

export default App;

// 🎨 Styles
const styles = {
  loader: {
    height: "100vh",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",
    background: "linear-gradient(135deg, #2563EB, #1E40AF)",
    color: "white",
  },

  logo: {
    width: "90px",
    height: "90px",
    marginBottom: "15px",
  },

  title: {
    margin: "10px 0",
    fontSize: "32px",
    fontWeight: "bold",
  },

  subtitle: {
    fontSize: "16px",
    opacity: 0.9,
  },
};
